            List<Integer> path = new ArrayList<>();
            path.add(start);
            dfs(start, mask, path, adj, label, maxLen);
        }

        return maxLen[0];
    }

    private static void dfs(int current, long mask, List<Integer> path, List<List<Integer>> adj, String label, int[] maxLen) {
